import unittest
import numpy as np
import pandas as pd
from unittest.mock import patch, MagicMock
import torch
from torch.utils.data import DataLoader

class TestCustomDataset(unittest.TestCase):

    def setUp(self):
        """设置测试数据"""
        self.X_data = np.random.rand(100, 4).astype(np.float32)
        self.y_data = np.random.randint(0, 2, size=(100,)).astype(np.int64)

    def test_dataset_initialization(self):
        """测试数据集初始化"""
        from torch.utils.data import Dataset

        # 模拟完整的CustomDataset类定义
        class CustomDataset(Dataset):
            def __init__(self, X, y):
                self.X = torch.FloatTensor(X)
                self.y = torch.LongTensor(y)

            def __len__(self):
                return len(self.X)

            def __getitem__(self, idx):
                return self.X[idx], self.y[idx]

        dataset = CustomDataset(self.X_data, self.y_data)

        # 测试数据类型转换
        self.assertIsInstance(dataset.X, torch.FloatTensor)
        self.assertIsInstance(dataset.y, torch.LongTensor)

        # 测试数据形状
        self.assertEqual(dataset.X.shape, (100, 4))
        self.assertEqual(dataset.y.shape, (100,))

        # 测试索引访问
        x_item, y_item = dataset[0]
        self.assertIsInstance(x_item, torch.Tensor)
        self.assertIsInstance(y_item, torch.Tensor)
        self.assertEqual(x_item.shape, (4,))
        self.assertEqual(y_item.shape, ())

    def test_dataset_length(self):
        """测试数据集长度"""
        from torch.utils.data import Dataset

        class CustomDataset(Dataset):
            def __init__(self, X, y):
                self.X = torch.FloatTensor(X)
                self.y = torch.LongTensor(y)

            def __len__(self):
                return len(self.X)

            def __getitem__(self, idx):
                return self.X[idx], self.y[idx]

        dataset = CustomDataset(self.X_data, self.y_data)
        self.assertEqual(len(dataset), 100)

    def test_dataloader_compatibility(self):
        """测试与DataLoader的兼容性"""
        from torch.utils.data import Dataset

        class CustomDataset(Dataset):
            def __init__(self, X, y):
                self.X = torch.FloatTensor(X)
                self.y = torch.LongTensor(y)

            def __len__(self):
                return len(self.X)

            def __getitem__(self, idx):
                return self.X[idx], self.y[idx]

        dataset = CustomDataset(self.X_data, self.y_data)
        dataloader = DataLoader(dataset, batch_size=10, shuffle=False)

        for batch_x, batch_y in dataloader:
            self.assertEqual(batch_x.shape, (10, 4))
            self.assertEqual(batch_y.shape, (10,))
            break  # 只测试第一个批次

    def test_empty_dataset(self):
        """测试空数据集"""
        from torch.utils.data import Dataset

        class CustomDataset(Dataset):
            def __init__(self, X, y):
                self.X = torch.FloatTensor(X)
                self.y = torch.LongTensor(y)

            def __len__(self):
                return len(self.X)

            def __getitem__(self, idx):
                return self.X[idx], self.y[idx]

        empty_X = np.array([]).reshape(0, 4).astype(np.float32)
        empty_y = np.array([]).astype(np.int64)

        dataset = CustomDataset(empty_X, empty_y)
        self.assertEqual(len(dataset), 0)

if __name__ == '__main__':
    unittest.main()
